import itertools
class Solution:
    def minIncrease(self, nums):
        n = len(nums)
        candidates = list(range(1, n - 1))
        bestCount = -1
        bestCost = None
        for size in range(len(candidates) + 1):
            for combo in itertools.combinations(candidates, size):
                ok = all(combo[i + 1] - combo[i] >= 2 for i in range(len(combo) - 1))
                if not ok:
                    continue
                cost = 0
                for i in combo:
                    need = max(nums[i - 1], nums[i + 1]) + 1
                    cost += max(0, need - nums[i])
                if len(combo) > bestCount or (len(combo) == bestCount and cost < bestCost):
                    bestCount = len(combo)
                    bestCost = cost
        return bestCost if bestCost is not None else 0

