class Solution:
    def minIncrease(self, nums) -> int:
        n = len(nums)
        L = n - 2
        if L <= 0:
            return 0
        costs = []
        for i in range(1, n - 1):
            need = max(nums[i - 1], nums[i + 1]) + 1
            costs.append(max(0, need - nums[i]))
        if L % 2 == 1:
            return sum(costs[j] for j in range(0, L, 2))
        k = L // 2
        base = sum(costs[2 * j + 1] for j in range(k))
        best = base
        cur = base
        for t in range(1, k + 1):
            cur = cur - costs[2 * (t - 1) + 1] + costs[2 * (t - 1)]
            if cur < best:
                best = cur
        return best

