var minIncrease = function(nums) {
    const n = nums.length;
    const L = n - 2;
    if (L <= 0) return 0;
    const costs = [];
    for (let i = 1; i < n - 1; i++) {
        const need = Math.max(nums[i - 1], nums[i + 1]) + 1;
        costs.push(Math.max(0, need - nums[i]));
    }
    if (L % 2 === 1) {
        let s = 0;
        for (let j = 0; j < L; j += 2) s += costs[j];
        return s;
    }
    const k = Math.floor(L / 2);
    let base = 0;
    for (let j = 0; j < k; j++) base += costs[2 * j + 1];
    let best = base;
    let cur = base;
    for (let t = 1; t <= k; t++) {
        cur = cur - costs[2 * (t - 1) + 1] + costs[2 * (t - 1)];
        if (cur < best) best = cur;
    }
    return best;
};
